def test_no_text_hard_excluded(tmp_path: Path) -> None:
    """A doc with no readable text scores ≤ −10 and is absent from select_chapters."""
    epub_path = tmp_path / "empty_doc.epub"
    build_empty_doc_epub(epub_path)
    candidates, _ = _open_and_score(epub_path)

    empty_candidates = [
        c for c in candidates
        if c.title and "empty" in c.title.lower()
    ]
    assert len(empty_candidates) >= 1, (
        f"Expected an 'empty' candidate; got: {[(c.title, c.score) for c in candidates]}"
    )
    for ec in empty_candidates:
        assert ec.score <= -10, (
            f"Empty document should score ≤ −10 (no-text = −10). "
            f"Got score={ec.score}, signals={ec.signals}"
        )

    chapters = select_chapters(candidates)
    chapter_titles = [ch.title.lower() for ch in chapters]
    assert not any("empty" in t for t in chapter_titles), (
        f"Empty doc should be excluded but appeared in: {chapter_titles}"
    )
